export const 複文大子 = (bi) => {
    const u = bi.u;
    const 線 = (書, 寬 = 0.85) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.9) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    // 大（雙）
    const 大 = (cx) => {
        線(p => p.M(cx - 2.4, 4.0).C(cx - 1.2, 3.7, cx + 1.2, 3.7, cx + 2.4, 4.0), 0.85);
        出(p => p.M(cx + 0.3, 2.3).C(cx - 0.3, 4.3, cx - 1.3, 6.1, cx - 2.8, 7.6), 0.9);
        出(p => p.M(cx - 0.4, 4.9).C(cx + 0.5, 5.9, cx + 1.5, 6.8, cx + 2.7, 7.5), 0.9);
    };
    大(-4.6);
    大(4.6);
    // 左子（帶亻旁）
    出(p => p.M(-6.9, 13.0).C(-7.3, 14.2, -7.7, 15.3, -8.2, 16.3), 0.75);
    線(p => p.M(-7.6, 15.0).L(-7.65, 20.8), 0.75);
    線(p => p.M(-6.0, 13.6).C(-5.3, 13.9, -4.4, 13.9, -3.0, 13.4), 0.85);
    出(p => p.M(-4.4, 13.6).C(-4.7, 15.5, -4.7, 17.3, -4.5, 19.0)
        .C(-4.4, 20.0, -5.1, 20.6, -6.2, 20.4), 0.9);
    線(p => p.M(-6.6, 16.4).L(-2.6, 16.1), 0.85);
    // 右子（曳大迴鉤）
    線(p => p.M(2.6, 13.4).C(3.4, 13.7, 4.4, 13.7, 6.0, 13.2), 0.85);
    出(p => p.M(4.4, 13.4).C(4.1, 15.4, 4.1, 17.4, 4.4, 19.2)
        .C(4.6, 20.6, 3.8, 21.5, 2.2, 21.4)
        .C(1.5, 21.3, 1.0, 21.0, 0.7, 20.5), 0.9);
    線(p => p.M(2.0, 16.4).L(6.4, 16.1), 0.85);
};
